// XorSwap swaps two integers using XOR without a temporary variable.
func XorSwap(a, b int) (int, int) {
	if a != b {
		a = a ^ b
		b = a ^ b
		a = a ^ b
	}
	return a, b
}

/**
 * XOR swap is an algorithm that uses the XOR bitwise operation to swap 
 * values of distinct variables without using a temporary variable. 
 * 
 * @author Atom
 * @see <a href="https://en.wikipedia.org/wiki/XOR_swap_algorithm">XOR swap</a>
 */
public class XorSwap {
    public static int[] xorSwap(int a, int b) {
        int x = a;
        int y = b;
        if (x != y) {
            x ^= y;
            y ^= x;
            x ^= y;
        }
        return new int[]{x, y};
    }

	public static void main(String[] args) {
		for (int i = -1, j = 3; i <= 3; i++, j--) {
			int x = i;
			int y = j;
			System.out.print("x = " + x + ", y = " + y);

			// Xor swap. Swap values without using a temporary variable
			if (x != y) {
				x ^= y;
				y ^= x;
				x ^= y;				
			}

			System.out.println(", swap(x, y) -> x = " + x + ", y = " + y);
		}
	}

}

fun xorSwap(a: Int, b: Int): Pair<Int, Int> {
    var x = a
    var y = b
    if (x != y) {
        x = x xor y
        y = x xor y
        x = x xor y
    }
    return Pair(x, y)
}

fun main() {
    val (a, b) = xorSwap(5, 10)
    println("After swap: a=$a, b=$b")
}

fn xor_swap(a: i32, b: i32) -> (i32, i32) {
    let mut x = a;
    let mut y = b;
    if x != y {
        x = x ^ y;
        y = x ^ y;
        x = x ^ y;
    }
    (x, y)
}

fn main() {
    let (a, b) = xor_swap(5, 10);
    println!("After swap: a={}, b={}", a, b);
}

